const V_MAX = 100000;
// We need a safe upper bound for the sieve. Since primes are dense, 
// searching slightly past 100000 should be safe for finding the next number.
const MAX_SIEVE = V_MAX + 200;

/**
 * Precomputes primality up to MAX_SIEVE using the Sieve of Eratosthenes.
 * @returns {boolean[]} An array where isPrime[i] is true if i is prime.
 */
function generateSieve() {
    const isPrime = new Array(MAX_SIEVE + 1).fill(true);
    isPrime[0] = isPrime[1] = false;

    for (let p = 2; p * p <= MAX_SIEVE; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= MAX_SIEVE; i += p)
                isPrime[i] = false;
        }
    }
    return isPrime;
}

// Global or static initialization of the sieve data structure
const isPrimeMap = generateSieve();

/**
 * Checks if a number is prime using the precomputed sieve.
 * Assumes n <= MAX_SIEVE.
 * @param {number} n 
 * @returns {boolean}
 */
function checkIsPrime(n) {
    if (n > MAX_SIEVE) {
        // Fallback check for safety, though ideally targets stay within MAX_SIEVE
        if (n <= 1) return false;
        for (let i = 2; i * i <= n; i++) {
            if (n % i === 0) return false;
        }
        return true;
    }
    return isPrimeMap[n];
}

function solve(nums) {
    let totalOperations = 0;

    for (let i = 0; i < nums.length; i++) {
        const currentVal = nums[i];
        let targetVal = currentVal;

        if (i % 2 === 0) {
            // EVEN index: Must be PRIME
            // Find smallest prime p >= currentVal
            while (true) {
                if (checkIsPrime(targetVal)) {
                    break;
                }
                targetVal++;
            }
        } else {
            // ODD index: Must be NON-PRIME
            // Find smallest non-prime np >= currentVal
            // A number is non-prime if it is 1 or composite.
            while (true) {
                if (!checkIsPrime(targetVal)) {
                    break;
                }
                targetVal++;
            }
        }

        totalOperations += (targetVal - currentVal);
    }

    return totalOperations;
}

